arguments.file_text:
@page "/shipments"
@using ShipmentTracker.Client.Models
@using ShipmentTracker.Client.Services
@using Microsoft.AspNetCore.Authorization
@attribute [Authorize]
@rendermode InteractiveAuto
@inject IShipmentService ShipmentService

<PageTitle>Shipment Dashboard</PageTitle>

<h1>Shipment Dashboard</h1>

<div class="mb-3">
    <button class="btn btn-primary" @onclick="ShowCreateForm">
        @(showCreateForm ? "Cancel" : "New Shipment")
    </button>
</div>

@if (showCreateForm)
{
    <div class="card mb-4">
        <div class="card-body">
            <h5 class="card-title">Create Shipment</h5>
            <EditForm Model="newShipment" OnValidSubmit="CreateShipment" FormName="createShipment">
                <DataAnnotationsValidator />
                <div class="row g-3">
                    <div class="col-md-6">
                        <label class="form-label">Origin</label>
                        <InputText class="form-control" @bind-Value="newShipment.Origin" />
                    </div>
                    <div class="col-md-6">
                        <label class="form-label">Destination</label>
                        <InputText class="form-control" @bind-Value="newShipment.Destination" />
                    </div>
                    <div class="col-md-6">
                        <label class="form-label">Customer Email</label>
                        <InputText class="form-control" @bind-Value="newShipment.CustomerEmail" />
                    </div>
                    <div class="col-md-6">
                        <label class="form-label">Description</label>
                        <InputText class="form-control" @bind-Value="newShipment.Description" />
                    </div>
                    <div class="col-md-6">
                        <label class="form-label">Estimated Delivery</label>
                        <InputDate class="form-control" @bind-Value="newShipment.EstimatedDelivery" />
                    </div>
                    <div class="col-12">
                        <button type="submit" class="btn btn-success">Create</button>
                    </div>
                </div>
            </EditForm>
        </div>
    </div>
}

@if (shipments == null)
{
    <p><em>Loading shipments...</em></p>
}
else if (shipments.Count == 0)
{
    <p>No shipments found.</p>
}
else
{
    <div class="mb-3">
        <input type="text" class="form-control" placeholder="Filter by destination..."
               @bind="filterText" @bind:event="oninput" />
    </div>

    <table class="table table-striped">
        <thead>
            <tr>
                <th>Tracking #</th>
                <th>Origin</th>
                <th>Destination</th>
                <th>Status</th>
                <th>Shipped</th>
                <th>Est. Delivery</th>
                <th>Actions</th>
            </tr>
        </thead>
        <tbody>
            @foreach (var shipment in FilteredShipments)
            {
                <tr>
                    <td><code>@shipment.TrackingNumber</code></td>
                    <td>@shipment.Origin</td>
                    <td>@shipment.Destination</td>
                    <td><span class="badge @GetStatusBadgeClass(shipment.Status)">@shipment.Status</span></td>
                    <td>@shipment.ShippedDate.ToString("yyyy-MM-dd")</td>
                    <td>@shipment.EstimatedDelivery.ToString("yyyy-MM-dd")</td>
                    <td>
                        <select class="form-select form-select-sm" style="width: auto; display: inline-block;"
                                @onchange="(e) => UpdateStatus(shipment, e)">
                            @foreach (var status in Enum.GetValues<ShipmentStatus>())
                            {
                                <option value="@status" selected="@(status == shipment.Status)">@status</option>
                            }
                        </select>
                    </td>
                </tr>
            }
        </tbody>
    </table>
}

@code {
    private List<ShipmentDto>? shipments;
    private string filterText = string.Empty;
    private bool showCreateForm;
    private ShipmentDto newShipment = new() { EstimatedDelivery = DateTime.Today.AddDays(5) };

    private IEnumerable<ShipmentDto> FilteredShipments =>
        shipments?.Where(s => string.IsNullOrEmpty(filterText)
            || s.Destination.Contains(filterText, StringComparison.OrdinalIgnoreCase)) ?? [];

    protected override async Task OnInitializedAsync()
    {
        shipments = await ShipmentService.GetAllShipmentsAsync();
    }

    private void ShowCreateForm() => showCreateForm = !showCreateForm;

    private async Task CreateShipment()
    {
        var created = await ShipmentService.CreateShipmentAsync(newShipment);
        shipments?.Insert(0, created);
        newShipment = new() { EstimatedDelivery = DateTime.Today.AddDays(5) };
        showCreateForm = false;
    }

    private async Task UpdateStatus(ShipmentDto shipment, ChangeEventArgs e)
    {
        if (Enum.TryParse<ShipmentStatus>(e.Value?.ToString(), out var newStatus))
        {
            var updated = await ShipmentService.UpdateShipmentStatusAsync(shipment.Id, newStatus);
            shipment.Status = updated.Status;
        }
    }

    private static string GetStatusBadgeClass(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Delivered => "bg-success",
        ShipmentStatus.InTransit => "bg-primary",
        ShipmentStatus.OutForDelivery => "bg-info",
        ShipmentStatus.Delayed => "bg-danger",
        ShipmentStatus.PickedUp => "bg-warning text-dark",
        _ => "bg-secondary"
    };
}

@page "/track"
@using ShipmentTracker.Client.Models
@using ShipmentTracker.Client.Services
@using Microsoft.AspNetCore.Authorization
@attribute [Authorize]
@rendermode InteractiveAuto
@inject IShipmentService ShipmentService

<PageTitle>Track Shipment</PageTitle>

<h1>Track Your Shipment</h1>

<div class="row mb-4">
    <div class="col-md-6">
        <div class="input-group">
            <input type="text" class="form-control" placeholder="Enter tracking number..."
                   @bind="trackingNumber" @bind:event="oninput"
                   @onkeydown="HandleKeyDown" />
            <button class="btn btn-primary" @onclick="SearchShipment" disabled="@isSearching">
                @if (isSearching)
                {
                    <span class="spinner-border spinner-border-sm" role="status"></span>
                }
                else
                {
                    <span>Track</span>
                }
            </button>
        </div>
    </div>
</div>

@if (searchPerformed && shipment == null)
{
    <div class="alert alert-warning">
        No shipment found with tracking number <strong>@searchedTracking</strong>.
    </div>
}

@if (shipment != null)
{
    <div class="card">
        <div class="card-header">
            <h5 class="mb-0">Shipment <code>@shipment.TrackingNumber</code></h5>
        </div>
        <div class="card-body">
            <div class="row">
                <div class="col-md-6">
                    <dl>
                        <dt>Description</dt>
                        <dd>@shipment.Description</dd>
                        <dt>Origin</dt>
                        <dd>@shipment.Origin</dd>
                        <dt>Destination</dt>
                        <dd>@shipment.Destination</dd>
                    </dl>
                </div>
                <div class="col-md-6">
                    <dl>
                        <dt>Status</dt>
                        <dd><span class="badge @GetStatusBadgeClass(shipment.Status) fs-6">@shipment.Status</span></dd>
                        <dt>Shipped Date</dt>
                        <dd>@shipment.ShippedDate.ToString("MMMM dd, yyyy")</dd>
                        <dt>Estimated Delivery</dt>
                        <dd class="fw-bold">@shipment.EstimatedDelivery.ToString("MMMM dd, yyyy")</dd>
                    </dl>
                </div>
            </div>

            <h6 class="mt-3">Delivery Progress</h6>
            <div class="progress" style="height: 30px;">
                <div class="progress-bar @GetProgressBarClass(shipment.Status)"
                     role="progressbar"
                     style="width: @(GetProgressPercent(shipment.Status))%"
                     aria-valuenow="@GetProgressPercent(shipment.Status)"
                     aria-valuemin="0" aria-valuemax="100">
                    @shipment.Status
                </div>
            </div>
        </div>
    </div>
}

@code {
    private string trackingNumber = string.Empty;
    private string searchedTracking = string.Empty;
    private ShipmentDto? shipment;
    private bool searchPerformed;
    private bool isSearching;

    private async Task HandleKeyDown(KeyboardEventArgs e)
    {
        if (e.Key == "Enter")
            await SearchShipment();
    }

    private async Task SearchShipment()
    {
        if (string.IsNullOrWhiteSpace(trackingNumber)) return;

        isSearching = true;
        searchedTracking = trackingNumber.Trim();
        shipment = await ShipmentService.GetShipmentByTrackingAsync(searchedTracking);
        searchPerformed = true;
        isSearching = false;
    }

    private static string GetStatusBadgeClass(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Delivered => "bg-success",
        ShipmentStatus.InTransit => "bg-primary",
        ShipmentStatus.OutForDelivery => "bg-info",
        ShipmentStatus.Delayed => "bg-danger",
        ShipmentStatus.PickedUp => "bg-warning text-dark",
        _ => "bg-secondary"
    };

    private static string GetProgressBarClass(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Delivered => "bg-success",
        ShipmentStatus.Delayed => "bg-danger",
        _ => "bg-primary"
    };

    private static int GetProgressPercent(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => 10,
        ShipmentStatus.PickedUp => 25,
        ShipmentStatus.InTransit => 50,
        ShipmentStatus.OutForDelivery => 75,
        ShipmentStatus.Delivered => 100,
        ShipmentStatus.Delayed => 50,
        _ => 0
    };
}

